features.snippet:
reg [31:0] data;
always @(*) data = a;
always @(*) data = b;

reg [31:0] temp;
always @(*) temp = input_data;
always @(*) out = temp;

always @(*) begin
for (i = 0; i < W_DATA; i = i + 1)
  out[i] = data[W_DATA-1-i];
end

reg [31:0] accum;
wire cond = accum[0];
always @(*) accum = cond ? a : b;
always @(*) accum = cond ? c : d;
